    Question(categoryId = 7, questionText = "Was ist ein Merkle Tree und welche zentrale Eigenschaft macht ihn fuer Blockchain-Systeme wertvoll?", answerA = "Eine Baumstruktur aus Hash-Werten, bei der jeder Elternknoten den Hash seiner zwei Kindknoten speichert und eine effiziente Integritaetspruefung einzelner Transaktionen erlaubt", answerB = "Ein binaerer Suchbaum fuer schnelle Datenbankabfragen", answerC = "Ein verschluesselter Speicherbereich fuer Private Keys", answerD = "Ein Protokoll zur Synchronisierung von Blockchain-Knoten", correctAnswer = 0, explanation = "Im Merkle Tree wird jede Transaktion gehasht. Paare von Hashes werden erneut gehasht, bis nur noch der Merkle Root uebrig bleibt. Eine einzelne Transaktion kann mit O(log n) Hashes verifiziert werden, ohne den ganzen Block zu kennen.", difficulty = 3, funFact = "Ralph Merkle patentierte die Struktur 1979. Bitcoin verwendet SHA-256-Merkle-Trees, Ethereum verwendet Merkle-Patricia-Tries fuer den State."),
    Question(categoryId = 7, questionText = "Was ist der wesentliche Unterschied zwischen Proof of Work und Proof of Stake hinsichtlich der Sybil-Resistenz?", answerA = "PoW bindet Einfluss an reale Rechenarbeit (Energie), PoS bindet Einfluss an gesperrtes Kapital (Stake) — beide verteuern dadurch Angriffe, aber auf unterschiedliche Ressourcen", answerB = "PoW und PoS haben identische Sicherheitsmodelle", answerC = "PoS erfordert mehr Energie als PoW", answerD = "PoW erlaubt anonyme Teilnahme, PoS nicht", correctAnswer = 0, explanation = "Sybil-Resistenz bedeutet, dass ein Angreifer nicht einfach viele Identitaeten erstellen kann. PoW zwingt ihn, reale Hardware und Strom zu kaufen; PoS zwingt ihn, 1/3 des gesamten Stakes zu besitzen.", difficulty = 3, funFact = "Ethereum wechselte im September 2022 mit 'The Merge' von PoW zu PoS und reduzierte damit seinen Energieverbrauch um ca. 99,95%."),
    Question(categoryId = 7, questionText = "Was ist Gas in der Ethereum Virtual Machine und warum ist es als Mechanismus notwendig?", answerA = "Gas ist eine Masseinheit fuer den Rechenaufwand einer EVM-Operation; es verhindert Denial-of-Service durch unendliche Schleifen, da jede Instruktion Gas kostet und Transaktionen ein Gas-Limit haben", answerB = "Gas ist der native Token von Ethereum", answerC = "Gas ist die Gebuehr fuer Netzwerk-Bandbreite beim Senden einer Transaktion", answerD = "Gas ist ein optionales Feature fuer kostenlose Transaktionen", correctAnswer = 0, explanation = "Ohne Gas koennte ein Angreifer eine Endlosschleife in einen Smart Contract einbauen und damit alle Ethereum-Knoten lahmlegen. Wenn das Gas-Limit erschoepft ist, wird die Transaktion rueckgaengig gemacht, aber die Gebuehr einbehalten.", difficulty = 3, funFact = "Der Gas-Preis wird in Gwei (10^-9 ETH) angegeben. EIP-1559 fuegte 2021 einen Base Fee-Mechanismus hinzu, der ETH verbrennt statt es an Miner zu zahlen."),
    Question(categoryId = 7, questionText = "Wie funktioniert ein Optimistic Rollup als Ethereum Layer-2-Loesung und was ist die Challengeperiode?", answerA = "Transaktionen werden off-chain ausgefuehrt und komprimiert on-chain gepostet; sie gelten als gueltig sofern innerhalb einer Challengeperiode (typisch 7 Tage) kein Betrugsnachweis eingereicht wird", answerB = "Optimistic Rollups verwenden ZK-Beweise zur sofortigen Verifikation jeder Transaktion", answerC = "Optimistic Rollups erfordern einen vertrauenswuerdigen Sequencer der alle Transaktionen signiert", answerD = "Die Challengeperiode betraegt standardmaessig 24 Stunden bei allen Optimistic Rollups", correctAnswer = 0, explanation = "Das 'Optimistic' bezieht sich darauf, dass das System davon ausgeht, dass Transaktionen ehrlich sind. Erst wenn ein Betrugsnachweis (Fraud Proof) eingereicht wird, wird die fehlerhafte Transaktion on-chain neu ausgefuehrt.", difficulty = 3, funFact = "Optimism und Arbitrum sind die groessten Optimistic Rollups. Die 7-Tage-Challengeperiode ist der Grund warum Auszahlungen auf L1 so lange dauern."),
    Question(categoryId = 7, questionText = "Was ist SLAM in der Robotik und welche zwei Teilprobleme muss es gleichzeitig loesen?", answerA = "Simultaneous Localization and Mapping: Ein Roboter muss gleichzeitig eine Karte seiner Umgebung erstellen (Mapping) und seine eigene Position in dieser Karte bestimmen (Localization) — beides haengt voneinander ab", answerB = "SLAM steht fuer Simultaneous Laser Alignment and Mapping", answerC = "SLAM ist ein Kommunikationsprotokoll zwischen mehreren Robotern", answerD = "SLAM beschreibt die Regelung von Servomotoren fuer praezise Bewegungen", correctAnswer = 0, explanation = "Das Huhn-Ei-Problem: Fuer gutes Mapping brauche ich meine genaue Position, aber fuer genaue Lokalisierung brauche ich eine gute Karte. Algorithmen wie EKF-SLAM und GraphSLAM loesen dies durch probabilistische Schaetzung.", difficulty = 3, funFact = "SLAM ist eines der schwierigsten Probleme der Robotik und der KI. Selbstfahrende Autos, Staubsaugerroboter und Mars-Rover verwenden alle Varianten von SLAM-Algorithmen."),
    Question(categoryId = 7, questionText = "Was ist Inverse Kinematik (IK) in der Robotik und warum ist sie schwieriger als Forward Kinematik?", answerA = "IK berechnet die Gelenkwinkel aus einer gewuenschten End-Effektor-Position; FK berechnet die End-Effektor-Position aus bekannten Gelenkwinkeln — IK hat oft keine eindeutige oder analytische Loesung", answerB = "IK und FK sind mathematisch aequivalent und gleich schwer zu berechnen", answerC = "IK wird nur fuer Greifarme verwendet, FK fuer mobile Roboter", answerD = "Forward Kinematik ist das schwierigere Problem da mehr Variablen berechnet werden muessen", correctAnswer = 0, explanation = "FK ist eine direkte Berechnung: gegeben Gelenkwinkel, berechne Position. IK ist die Umkehrung: gegeben Zielposition, finde Gelenkwinkel. IK kann nicht-eindeutig (mehrere Loesungen) oder nicht loesbar sein und erfordert numerische oder heuristische Methoden.", difficulty = 3, funFact = "Der menschliche Arm hat 7 Freiheitsgrade — mehr als die 6 die noetig sind um jeden Punkt im Raum zu erreichen. Dieser 'Redundanzgrad' macht IK fuer den Arm unendlich viele Loesungen moeglich."),
    Question(categoryId = 7, questionText = "Was ist Quantendekohaerenz und warum stellt sie die groesste praktische Huerde fuer Quantencomputer dar?", answerA = "Dekohaerenz ist der Prozess bei dem Qubits durch Wechselwirkung mit der Umgebung ihre Quanteneigenschaften verlieren und sich klassisch verhalten", answerB = "Dekohaerenz beschreibt das Abkuehlen von Quantenprozessoren auf Betriebstemperatur", answerC = "Dekohaerenz ist ein gewuenschter Effekt der Quantenmessungen beschleunigt", answerD = "Quantendekohaerenz betrifft nur supraleitende Qubits, nicht Ionen-Fallen-Systeme", correctAnswer = 0, explanation = "Jedes Quantensystem interagiert mit seiner Umgebung (thermisches Rauschen, elektromagnetische Felder) und verliert dabei seine Superposition. Die Kohaerenzzeit — oft Mikrosekunden bei supraleitenden Qubits — begrenzt die moegliche Schaltkreistiefe.", difficulty = 3, funFact = "IBMs Quantenprozessoren laufen bei 15 Millikelvin — kaelter als der Weltraum (2,7 K). Diese extreme Kaelte ist noetig um Dekohaerenz zu minimieren."),
    Question(categoryId = 7, questionText = "Was ist das Blockchain-Trilemma nach Vitalik Buterin und welche drei Eigenschaften stehen im Konflikt?", answerA = "Das Trilemma beschreibt den Konflikt zwischen Skalierbarkeit, Sicherheit und Dezentralisierung — ein Blockchain-System kann maximal zwei davon gleichzeitig vollstaendig optimieren", answerB = "Das Blockchain-Trilemma beschreibt den Konflikt zwischen Geschwindigkeit, Kosten und Datenschutz", answerC = "Das Trilemma ist ein veraltetes Konzept das durch Sharding vollstaendig geloest wurde", answerD = "Das Blockchain-Trilemma betrifft nur permissioned Blockchains", correctAnswer = 0, explanation = "Bitcoin waehlt Sicherheit und Dezentralisierung auf Kosten der Skalierbarkeit (7 TPS). Binance Smart Chain waehlt Skalierbarkeit und Sicherheit auf Kosten der Dezentralisierung (21 Validatoren). Layer-2-Loesungen versuchen, alle drei zu erhalten.", difficulty = 3, funFact = "Ethereum Danksharding (geplant 2025+) soll durch Proto-Danksharding (EIP-4844) die Kapazitaet fuer Rollup-Daten drastisch erhoehen ohne das Trilemma vollstaendig aufzuloesen."),
    Question(categoryId = 7, questionText = "Was ist Return-Oriented Programming (ROP) und welche Schutzmassnahmen soll es umgehen?", answerA = "ROP verkettet kleine Befehlssequenzen (Gadgets) die bereits im Prozess vorhanden sind und mit RET enden um beliebigen Code auszufuehren ohne eigenen Code einzuschleusen; umgeht NX/DEP", answerB = "ROP ist eine Programmierparadigma fuer eingebettete Systeme", answerC = "ROP ist ein Return-Mechanismus fuer Mikroprozessoren", answerD = "ROP bezeichnet rueckwaertskompatibles Programmieren auf alten Architekturen", correctAnswer = 0, explanation = "Da NX/DEP den Stack als nicht-ausfuehrbar markiert, kann kein Shellcode injiziert werden. ROP verwendet stattdessen 'Gadgets' aus dem bestehenden Code (libc, ntdll) um Shellcode-Effekte zu erzielen.", difficulty = 3, funFact = "Hovav Shacham bewies 2007, dass ROP Turing-vollstaendig ist. ASLR und CFI (Control Flow Integrity) sind die wichtigsten Gegenmassnahmen."),
    Question(categoryId = 7, questionText = "Was ist das STRIDE-Bedrohungsmodell und welche sechs Bedrohungskategorien umfasst es?", answerA = "STRIDE (Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, Elevation of Privilege) ist ein Bedrohungsmodellierungsrahmen von Microsoft zur systematischen Sicherheitsanalyse von Systemen", answerB = "STRIDE ist ein symmetrisches Verschluesselungsverfahren", answerC = "STRIDE beschreibt Netzwerkschichten in der Cybersecurity", answerD = "STRIDE ist ein Pentesting-Framework mit sechs Angriffsphasen", correctAnswer = 0, explanation = "Jede STRIDE-Kategorie hat ein entsprechendes Sicherheitsziel: Spoofing-Authentizitaet, Tampering-Integritaet, Repudiation-Nicht-Abstreitbarkeit, Info Disclosure-Vertraulichkeit, DoS-Verfuegbarkeit, EoP-Autorisierung.", difficulty = 3, funFact = "STRIDE wurde von Loren Kohnfelder und Praerit Garg bei Microsoft 1999 entwickelt. Es wird heute durch DREAD (Damage, Reproducibility, Exploitability, Affected Users, Discoverability) fuer Risikobewertung ergaenzt."),
    Question(categoryId = 7, questionText = "Was ist das Konzept eines 'Trusted Execution Environment' (TEE) und welche Implementierungen gibt es?", answerA = "Ein TEE ist eine hardwaregeschuetzte Ausfuehrungsumgebung innerhalb der CPU die Code und Daten vor dem Betriebssystem und Hypervisor isoliert; Implementierungen sind Intel SGX, ARM TrustZone und AMD SEV", answerB = "TEE ist ein Hardwareverschluesselungsmodul fuer Festplatten", answerC = "TEE ist ausschliesslich in Smartcards implementiert", answerD = "TEEs benoetigen immer eine Netzwerkverbindung zu einem Verifikationsserver", correctAnswer = 0, explanation = "Intel SGX erstellt 'Enclaves' im Speicher die selbst der OS-Kernel nicht lesen kann. ARM TrustZone teilt den Prozessor in Normal- und Secure-World. Remote Attestation erlaubt es, die Integritaet der TEE-Software zu verifizieren.", difficulty = 3, funFact = "Signal nutzt TEE (Intel SGX) fuer seine 'Sealed Sender'-Funktion auf den Signal-Servern. Schwachstellen wie Foreshadow (2018) und LVI haben jedoch gezeigt, dass TEEs nicht unfehlbar sind."),
    Question(categoryId = 7, questionText = "Was ist differenzielle Kryptoanalyse und gegen welche Chiffre wurde sie urspruenglich entwickelt?", answerA = "Differenzielle Kryptoanalyse untersucht wie sich Differenzen in Klartextpaaren auf Differenzen in den Chiffretextpaaren auswirken um Informationen ueber den Schluessel zu gewinnen; urspruenglich gegen DES entwickelt", answerB = "Differenzielle Kryptoanalyse analysiert Unterschiede in den Schluesseln symmetrischer Chiffren", answerC = "Die Methode wird ausschliesslich gegen asymmetrische Kryptosysteme eingesetzt", answerD = "Differenzielle Kryptoanalyse erfordert Zugriff auf den Schluessel", correctAnswer = 0, explanation = "Eli Biham und Adi Shamir entwickelten 1990 die differenzielle Kryptoanalyse und demonstrierten sie gegen DES. IBM hatte das Prinzip intern seit den 1970ern gekannt und die S-Boxen von DES extra dagegen gehaertet.", difficulty = 3, funFact = "AES S-Boxen wurden explizit mit Widerstand gegen differenzielle und lineare Kryptoanalyse als Designkriterium gebaut. Der optimale differenzielle Widerstand der AES-S-Box ist beweisbar maximal."),
    Question(categoryId = 7, questionText = "Was ist das Konzept 'Secure by Design' und wie unterscheidet es sich vom Ansatz 'Security by Obscurity'?", answerA = "Secure by Design baut Sicherheit als fundamentale Eigenschaft in Architektur und Implementierung ein; Security by Obscurity versucht Sicherheit durch Geheimhaltung der Implementierung zu erreichen — was nach Kerckhoffs' Prinzip als unzureichend gilt", answerB = "Secure by Design und Security by Obscurity sind gleichwertige Ansaetze mit unterschiedlichen Implementierungen", answerC = "Security by Obscurity ist laut NIST der bevorzugte Ansatz fuer Bundesbehoerden", answerD = "Secure by Design bedeutet dass Software nach dem Schreiben sicherheitsgepruefte wird", correctAnswer = 0, explanation = "Kerckhoffs' Prinzip (1883): Ein Kryptosystem muss sicher sein auch wenn alles ausser dem Schluessel bekannt ist. Security by Obscurity faellt zusammen sobald die Implementierung bekannt wird — was bei Open Source oder Reverse Engineering unvermeidlich ist.", difficulty = 3, funFact = "Claude Shannon formulierte Kerckhoffs' Prinzip als 'the enemy knows the system'. Alle modernen Kryptosysteme (AES, RSA, TLS) sind oeffentlich spezifiziert und ihre Sicherheit haengt nur vom geheimen Schluessel ab."),

    // correctAnswer = 1 (13 Fragen)
    Question(categoryId = 7, questionText = "Wie funktioniert der Nakamoto-Konsens (Proof of Work) und welches Problem loest er im verteilten System?", answerA = "Knoten stimmen per Mehrheitsvotum ueber neue Bloecke ab", answerB = "Miner loesen ein kryptografisches Raetsel (Finden einer Nonce sodass der Block-Hash unter einem Zielwert liegt), was rechenintensiv ist und das Byzantine-Generals-Problem loest", answerC = "Validatoren hinterlegen Kapital als Sicherheit und verlieren es bei Betrug", answerD = "Knoten rotieren nach einem festgelegten Zeitplan als Block-Produzenten", correctAnswer = 1, explanation = "PoW macht das Faelschen eines Blocks kostspielig: Ein Angreifer muesste mehr Rechenleistung als 50% des Netzwerks aufbringen. Die laengste Kette gilt als kanonisch.", difficulty = 3, funFact = "Satoshi Nakamotos Whitepaper loeste 2008 das seit 1982 offene Byzantine Generals Problem fuer permissionlose Systeme erstmals praktisch."),
    Question(categoryId = 7, questionText = "Was versteht man unter dem CAP-Theorem in Bezug auf dezentrale Blockchain-Netzwerke?", answerA = "Jedes verteilte System kann Consistency, Availability und Partition Tolerance gleichzeitig vollstaendig garantieren", answerB = "Ein verteiltes System kann bei einer Netzwerkpartition nur zwei der drei Eigenschaften Consistency, Availability und Partition Tolerance gleichzeitig garantieren; Blockchains waehlen typischerweise CP", answerC = "Das CAP-Theorem gilt nur fuer relationale Datenbanken, nicht fuer Blockchains", answerD = "Blockchain-Systeme garantieren immer alle drei CAP-Eigenschaften durch Sharding", correctAnswer = 1, explanation = "Bitcoin und Ethereum waehlen Konsistenz (CP): Bei einer Partition haelt das Netzwerk an und akzeptiert keine neuen Bloecke, bis die Verbindung wiederhergestellt ist. Nur wenige Blockchains opfern Konsistenz fuer Verfuegbarkeit.", difficulty = 3, funFact = "Eric Brewer formulierte das CAP-Theorem 2000 als Vermutung; Seth Gilbert und Nancy Lynch bewiesen es 2002 formal."),
    Question(categoryId = 7, questionText = "Was ist der Zweck des EVM-Opcodes SSTORE und was unterscheidet ihn von MSTORE hinsichtlich der Gas-Kosten?", answerA = "SSTORE und MSTORE sind identisch — beide schreiben in den persistenten Speicher", answerB = "SSTORE schreibt in den persistenten Contract Storage (teuer: 20.000 Gas fuer neue Slots) waehrend MSTORE in den fluechtigen Memory schreibt (guenstig: 3 Gas) der nach der Transaktion verschwindet", answerC = "SSTORE ist ein veralteter Opcode der durch MSTORE ersetzt wurde", answerD = "MSTORE schreibt in den persistenten Speicher, SSTORE in den Stack", correctAnswer = 1, explanation = "Contract Storage ist Teil des Ethereum State Trie und muss von allen Knoten dauerhaft gespeichert werden — daher die hohen Kosten. Memory ist nur waehrend der Transaktionsausfuehrung vorhanden.", difficulty = 3, funFact = "EIP-2929 (Berlin Hardfork 2021) erhoehte die SLOAD-Kosten von 800 auf 2.100 Gas um Storage-bezogene DoS-Angriffe zu mitigieren."),
    Question(categoryId = 7, questionText = "Was unterscheidet einen ZK-Rollup von einem Optimistic Rollup fundamental?", answerA = "ZK-Rollups sind immer langsamer und teurer als Optimistic Rollups", answerB = "ZK-Rollups liefern kryptografische Gueltigkeit-Beweise (ZK-SNARKs/STARKs) fuer jeden Batch, sodass keine Challengeperiode noetig ist und Auszahlungen sofort finalisiert werden koennen", answerC = "ZK-Rollups setzen auf Betrugs-Beweise statt auf Gueltigkeit-Beweise", answerD = "Optimistic Rollups sind sicherer als ZK-Rollups", correctAnswer = 1, explanation = "Ein ZK-Beweis zeigt mathematisch, dass alle Transaktionen im Batch korrekt waren, ohne die Transaktionen selbst preiszugeben. Die Verifizierung des Beweises on-chain ist guenstig und sofortig.", difficulty = 3, funFact = "StarkNet nutzt STARKs (ohne Trusted Setup), waehrend zkSync Era ZK-SNARKs verwendet. ZK-EVMs sind technisch extrem komplex und gelten als Meisterleistung der Kryptografie."),
    Question(categoryId = 7, questionText = "Was ist ein Reentrancy-Angriff in Ethereum Smart Contracts und welcher historische Hack ist darauf zurueckzufuehren?", answerA = "Ein Angriff der die Gaskosten einer Funktion kuenstlich erhoeht", answerB = "Ein Angriff bei dem ein boesartiger Contract eine Funktion des angegriffenen Contracts rekursiv aufruft bevor der Kontostand aktualisiert wird; beruehmt durch den DAO-Hack 2016", answerC = "Ein Cross-Site-Scripting-Angriff auf Ethereum-Wallets", answerD = "Ein Flashloan-Angriff auf dezentrale Boersen", correctAnswer = 1, explanation = "Der DAO-Hack nutzte aus, dass der Saldo erst nach dem ETH-Transfer aktualisiert wurde. Der Angreifer liess seinen Contract bei jedem Eingang von ETH erneut die Auszahlfunktion aufrufen — rekursiv — und stahl 3,6 Mio. ETH.", difficulty = 3, funFact = "Der DAO-Hack fuehrte zur kontroversen Ethereum-Hard-Fork und zur Spaltung in ETH und ETC. Das Checks-Effects-Interactions-Pattern verhindert Reentrancy."),
    Question(categoryId = 7, questionText = "Wie funktioniert Address Space Layout Randomization (ASLR) und welche Angriffstechnik umgeht es haeufig?", answerA = "ASLR verschluesselt alle Speicheradressen mit einem Session-Schluessel", answerB = "ASLR randomisiert die Basisadressen von Stack, Heap und Bibliotheken bei jedem Programmstart; Heap-Spray und Information-Leak-Angriffe koennen die Randomisierung unterwandern", answerC = "ASLR ist nur auf 64-Bit-Systemen effektiv", answerD = "ASLR verhindert Puffer-Ueberlaeufe vollstaendig", correctAnswer = 1, explanation = "Ohne ASLR liegt libc immer an der gleichen Adresse und ROP-Gadgets koennen hart kodiert werden. Mit ASLR muss der Angreifer zuerst eine Adresse leaken (Information Leak) um die Basis zu berechnen.", difficulty = 3, funFact = "Auf 32-Bit-Systemen hat ASLR nur 16 Bit Entropie (~65.000 Moeglichkeiten) und kann per Brute-Force umgangen werden. 64-Bit-ASLR mit 40+ Bit Entropie ist praktisch unknackbar ohne Info-Leak."),
    Question(categoryId = 7, questionText = "Was ist SQL Injection der zweiten Ordnung (Second-Order SQL Injection) und warum ist sie schwerer zu erkennen?", answerA = "Eine SQL Injection die zwei Parameter gleichzeitig angreift", answerB = "Schadhafter SQL-Code wird zuerst sicher in der Datenbank gespeichert und erst bei einem spaeterem Abruf — ohne erneute Validierung — in einer anderen Query ausgefuehrt", answerC = "Eine SQL Injection die nur auf gespeicherte Prozeduren abzielt", answerD = "Second-Order SQL Injection ist ein veraltetes Konzept ohne praktische Relevanz", correctAnswer = 1, explanation = "Beispiel: Ein Angreifer registriert sich mit dem Nutzernamen 'admin'--'. Beim Login wird dieser Name aus der DB geholt und in ein UPDATE eingefuegt. Die zweite Query ist injizierbar.", difficulty = 3, funFact = "Second-Order Injections umgehen viele WAFs und Input-Validierungen, da der schadhafte Code beim Einspeichern korrekt aussieht. Prepared Statements verhindern beide Arten."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Reflected XSS, Stored XSS und DOM-based XSS?", answerA = "Alle drei XSS-Varianten sind identisch — nur der Angriffsvektor unterscheidet sich minimal", answerB = "Reflected: Payload in URL-Parameter, wird einmalig reflektiert; Stored: Payload in Datenbank gespeichert, trifft alle Besucher; DOM-based: Manipulation des DOM durch JavaScript ohne Serverkontakt", answerC = "DOM-based XSS erfordert immer Server-side Code", answerD = "Stored XSS ist weniger gefaehrlich als Reflected XSS", correctAnswer = 1, explanation = "DOM-based XSS ist besonders heimtueckisch, da er vollstaendig clientseitig stattfindet — serverseitige Log-Analyse und WAFs koennen ihn oft nicht erkennen. Stored XSS trifft alle Besucher einer Seite.", difficulty = 3, funFact = "Der MySpace-Wurm Samy (2005) nutzte Stored XSS und infizierte in 20 Stunden ueber eine Million Profile — der schnellste Computerwurm seiner Zeit."),
    Question(categoryId = 7, questionText = "Was ist ein Qubit und wie unterscheidet es sich grundlegend von einem klassischen Bit?", answerA = "Ein Qubit kann nur die Werte 0 und 1 annehmen wie ein klassisches Bit, ist aber schneller zu verarbeiten", answerB = "Ein Qubit kann sich in einer Superposition aus 0 und 1 befinden und wird durch einen Zustandsvektor im zweidimensionalen komplexen Hilbert-Raum beschrieben; erst bei der Messung kollabiert es auf 0 oder 1", answerC = "Ein Qubit speichert immer beide Werte 0 und 1 gleichzeitig und verdoppelt so die Rechenkraft", answerD = "Ein Qubit ist ein Quantenbit das immer den Wert 0,5 hat bis es gemessen wird", correctAnswer = 1, explanation = "Der Quantenzustand |psi> = alpha|0> + beta|1> mit |alpha|^2 + |beta|^2 = 1. Die Amplitude alpha^2 ist die Wahrscheinlichkeit 0 zu messen. Superposition allein bringt keine Beschleunigung — erst Interferenz und Verschraenkung machen Quantencomputer maechtig.", difficulty = 3, funFact = "Ein einzelnes Qubit kann 2 Amplituden kodieren; n Qubits koennen 2^n Amplituden. Bei 300 Qubits waere das mehr Amplituden als Atome im beobachtbaren Universum."),
    Question(categoryId = 7, questionText = "Was ist das Hadamard-Gatter und welchen Quantenzustand erzeugt es aus dem Grundzustand |0>?", answerA = "Das Hadamard-Gatter negiert ein Qubit und erzeugt aus |0> den Zustand |1>", answerB = "Das Hadamard-Gatter erzeugt aus |0> die gleichmaessige Superposition (|0>+|1>)/sqrt(2) und ist sein eigenes Inverses", answerC = "Das Hadamard-Gatter ist das Quantenaequivalent des NAND-Gatters", answerD = "Das Hadamard-Gatter verdoppelt die Amplitude des Grundzustands", correctAnswer = 1, explanation = "H|0> = (|0>+|1>)/sqrt(2), H|1> = (|0>-|1>)/sqrt(2). Das Hadamard-Gatter ist eine unitaere 2x2-Matrix und bildet die Grundlage fast jeden Quantenalgorithmus, da es Superposition erzeugt.", difficulty = 3, funFact = "Das Hadamard-Gatter ist nach Jacques Hadamard benannt, einem franzoesischen Mathematiker der 1893 die Hadamard-Matrix einfuehrte — Jahrzehnte vor der Quanteninformatik."),
    Question(categoryId = 7, questionText = "Was ist ein Timing-Angriff auf kryptografische Implementierungen und wie wird er verhindert?", answerA = "Ein Angriff der die CPU-Auslastung waehrend der Verschluesselung misst", answerB = "Durch Messung der Ausfuehrungszeit einer kryptografischen Operation kann ein Angreifer geheime Schluesselbits ableiten; verhindert durch zeitkonstante (constant-time) Implementierungen", answerC = "Timing-Angriffe sind nur in Seitenkanal-Laborumgebungen moeglich", answerD = "Timing-Angriffe betreffen ausschliesslich symmetrische Verschluesselung", correctAnswer = 1, explanation = "Beispiel: RSA-Implementierungen die vorzeitig bei einem 0-Bit abbrechen sind schneller. Durch viele Zeitmessungen kann ein Angreifer den privaten Schluessel Bit-fuer-Bit rekonstruieren. Constant-time-Code laeuft immer gleich lang.", difficulty = 3, funFact = "Paul Kocher beschrieb 1996 Timing-Angriffe auf RSA und entwickelte 1998 Differential Power Analysis (DPA) gegen Smartcards. DPA hat praktisch jede damalige Smartcard kompromittiert."),
    Question(categoryId = 7, questionText = "Was ist Cross-Site Request Forgery (CSRF) und welche Schutzmassnahmen gibt es?", answerA = "CSRF ist eine Form von SQL Injection die Cross-Site-Daten manipuliert", answerB = "CSRF verleitet den Browser eines authentifizierten Nutzers dazu, ungewollt Requests an eine Webanwendung zu senden; Schutzmassnahmen sind CSRF-Tokens, SameSite-Cookie-Attribute und Referer-Validierung", answerC = "CSRF betrifft ausschliesslich APIs die keine Cookies verwenden", answerD = "CSRF-Angriffe erfordern JavaScript und koennen durch Content-Security-Policy vollstaendig verhindert werden", correctAnswer = 1, explanation = "Ein CSRF-Angriff: Eine boesartige Seite sendet einen POST-Request an bank.de/transfer. Da der Browser die Bank-Cookies automatisch mitschickt, akzeptiert die Bank den Request als authentifiziert. CSRF-Tokens binden Requests an die Session.", difficulty = 3, funFact = "SameSite=Strict oder Lax bei Cookies verhindert CSRF weitgehend da Cookies bei Cross-Site-Requests nicht mitgesendet werden. Es hat seit 2020 die meisten CSRF-Angriffe auf modernen Browsern eliminiert."),
    Question(categoryId = 7, questionText = "Was ist ein DMA-Angriff und welche Hardware-Schutzmechanismen schuetzen dagegen?", answerA = "DMA-Angriffe sind Software-Angriffe ueber Netzwerkschnittstellen", answerB = "Ein DMA-Angriff nutzt Direct Memory Access ueber PCIe/Thunderbolt um physischen Speicher des Rechners zu lesen oder zu schreiben ohne CPU-Beteiligung; IOMMU (Intel VT-d, AMD-Vi) schuetzt durch Speicherabbildung fuer DMA-faehige Geraete", answerC = "DMA-Angriffe betreffen nur virtuelle Maschinen", answerD = "IOMMU kann DMA-Angriffe nicht verhindern", correctAnswer = 1, explanation = "Ein Angreifer steckt ein praepariertes PCIe- oder Thunderbolt-Geraet ein und liest RAM direkt aus — inkl. Verschluesselungsschluesseln und RAM-Dumps. IOMMU begrenzt welche Speicherbereiche ein Geraet per DMA erreichen darf.", difficulty = 3, funFact = "Tools wie PCILeech und FPGA-basierte DMA-Karten erlauben DMA-Angriffe gegen ungeschuetzte Systeme. Kernel DMA Protection (Windows 10) und Thunderbolt-Zugangskontrolle mitigieren das Risiko."),

    // correctAnswer = 2 (12 Fragen)
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Stack-basierten Buffer Overflow und einem Heap-basierten Buffer Overflow?", answerA = "Stack-Overflows ueberschreiben nur lokale Variablen, Heap-Overflows sind harmloser", answerB = "Heap-Overflows sind nur auf Windows-Systemen moeglich", answerC = "Stack-Overflows ueberschreiben die Ruecksprungadresse auf dem Stack um Kontrollflusskontrolle zu uebernehmen; Heap-Overflows korrumpieren dynamisch allokierte Strukturen wie Funktionszeiger oder Objekt-Metadaten", answerD = "Stack-Overflows erfordern immer einen Debugger um ausgefuehrt zu werden", correctAnswer = 2, explanation = "Stack-Overflows erlauben klassisches Return-Adress-Ueberschreiben fuer ROP-Chains. Heap-Overflows sind komplexer: Sie korrumpieren Heap-Metadaten, Objekt-Vtables oder benachbarte Puffer um Code-Ausfuehrung zu erzielen.", difficulty = 3, funFact = "Aleph One's legendaerer Artikel 'Smashing the Stack for Fun and Profit' (1996) beschrieb Stack-Overflows erstmals oeffentlich und praegt die Security-Community bis heute."),
    Question(categoryId = 7, questionText = "Was versteht man unter einem Zero-Day-Exploit und was unterscheidet ihn von einem N-Day-Exploit?", answerA = "Zero-Day bedeutet dass der Exploit an einem Montag entdeckt wurde", answerB = "Zero-Day und N-Day sind Synonyme fuer denselben Angriffstyp", answerC = "Ein Zero-Day-Exploit nutzt eine Schwachstelle die dem Hersteller noch nicht bekannt ist und fuer die kein Patch existiert; N-Day bezeichnet Exploits fuer bekannte aber noch ungepatchte Schwachstellen", answerD = "Zero-Day-Exploits betreffen nur Betriebssysteme, nicht Anwendungssoftware", correctAnswer = 2, explanation = "Zero-Days sind extrem wertvoll auf dem Schwarzmarkt (100.000 bis mehrere Millionen USD) weil es keine Abwehrmassnahme gibt. N-Days sind billiger aber trotzdem gefaehrlich, da viele Systeme ungepatchet bleiben.", difficulty = 3, funFact = "Stuxnet nutzte vier Zero-Day-Exploits gleichzeitig — eine beispiellose Sophistiziertheit die auf staatliche Akteure hindeutete. Es wurde als cyberkinetische Waffe gegen iranische Zentrifugen eingesetzt."),
    Question(categoryId = 7, questionText = "Was ist das Roboter-Betriebssystem ROS und welches Grundprinzip liegt seiner Architektur zugrunde?", answerA = "ROS ist ein vollstaendiges Betriebssystem fuer Echtzeit-Mikrocontroller", answerB = "ROS ist eine proprietaere Plattform von Boston Dynamics", answerC = "ROS (Robot Operating System) ist ein Middleware-Framework mit einer publish-subscribe-Architektur: Nodes kommunizieren ueber Topics, Services und Actions ohne direkte Kopplung", answerD = "ROS kommuniziert ausschliesslich ueber serielle Schnittstellen", correctAnswer = 2, explanation = "Ein Kamera-Node publiziert Bilder auf /camera/image. Ein Erkennungs-Node subscribed auf dieses Topic, verarbeitet die Bilder und publiziert Erkennungen. Jeder Node ist ein eigener Prozess; ROS vermittelt die Kommunikation.", difficulty = 3, funFact = "ROS2 (ab 2017) ersetzte den zentralen ROS-Master durch DDS (Data Distribution Service) und unterstuetzt nun Echtzeit-Faehigkeiten und QoS-Einstellungen fuer kritische Anwendungen."),
    Question(categoryId = 7, questionText = "Was ist Quantenverschraenkung (Entanglement) und welche Konsequenz hat sie fuer die Messung verschraenkter Qubits?", answerA = "Quantenverschraenkung bedeutet, dass zwei Qubits physisch miteinander verbunden sein muessen", answerB = "Quantenverschraenkung erlaubt schnellere als Licht-Kommunikation", answerC = "Zwei verschraenkte Qubits koennen nicht unabhaengig beschrieben werden; die Messung eines Qubits bestimmt instantan den Zustand des anderen — unabhaengig von der Distanz zwischen ihnen", answerD = "Verschraenkte Qubits muessen immer denselben Messwert ergeben", correctAnswer = 2, explanation = "Ein Bell-Zustand: |phi+> = (|00>+|11>)/sqrt(2). Misst man das erste Qubit als 0, kollabiert das zweite instantan auf 0. Einstein nannte dies 'spukhafte Fernwirkung'. Keine Information wird uebertragen — das Ergebnis ist zufaellig.", difficulty = 3, funFact = "Bell-Tests von Alain Aspect (1982) und Zeilinger (2022 Nobelpreis) bewiesen, dass Verschraenkung real ist und nicht durch 'verborgene Variablen' erklaert werden kann."),
    Question(categoryId = 7, questionText = "Was ist Shors Algorithmus und welches klassische Kryptosystem gefaehrdet er?", answerA = "Shors Algorithmus loest das Travelling-Salesman-Problem in polynomialer Zeit und gefaehrdet symmetrische Verschluesselung", answerB = "Shors Algorithmus beschleunigt symmetrische Verschluesselung wie AES um den Faktor 2", answerC = "Shors Algorithmus faktorisiert grosse Zahlen in polynomialer Zeit auf einem Quantencomputer und gefaehrdet RSA, das auf der Schwierigkeit der Primfaktorzerlegung basiert", answerD = "Shors Algorithmus loest diskrete Logarithmen nur auf elliptischen Kurven", correctAnswer = 2, explanation = "RSA beruht darauf, dass klassische Computer zum Faktorisieren einer 2048-Bit-Zahl laenger als das Universum alt ist brauchen. Shors Algorithmus erledigt dies in O((log N)^3) Quantenoperationen.", difficulty = 3, funFact = "Ein Quantencomputer mit ca. 4.000 fehlerkorrigierten logischen Qubits koennte RSA-2048 in Stunden knacken. NIST standardisiert deshalb Post-Quanten-Kryptografie (CRYSTALS-Kyber, DILITHIUM)."),
    Question(categoryId = 7, questionText = "Was ist eine Hash-Kollision im kryptografischen Kontext und welchen Angriff ermoeglicht der Birthday-Paradox-Effekt?", answerA = "Eine Hash-Kollision tritt auf wenn zwei identische Eingaben unterschiedliche Hashes erzeugen", answerB = "Hash-Kollisionen sind bei kryptografischen Hash-Funktionen mathematisch unmoeglich", answerC = "Eine Kollision entsteht wenn zwei unterschiedliche Eingaben denselben Hash-Wert erzeugen; der Birthday-Angriff findet eine Kollision mit nur O(2^(n/2)) statt O(2^n) Versuchen aufgrund des Geburtstagsparadoxons", answerD = "Der Birthday-Angriff verdoppelt die Sicherheit einer Hash-Funktion", correctAnswer = 2, explanation = "Mit 23 Personen in einem Raum ist die Kollisionswahrscheinlichkeit fuer Geburtstage >50%. Analog: Bei 2^(n/2) zufaelligen Hashes ist eine Kollision wahrscheinlich. SHA-256 hat 256 Bit — Birthday-Angriff braucht 2^128 Versuche, immer noch sicher.", difficulty = 3, funFact = "MD5 wurde 2004 kollisionsgebrochen (Wang et al.) und 2008 wurde ein boesartiges CA-Zertifikat mit MD5-Kollisionen erstellt. SHA-1 wurde 2017 durch den SHAttered-Angriff von Google kollisionsgebrochen."),
    Question(categoryId = 7, questionText = "Was ist ein Pass-the-Hash-Angriff in Windows-Netzwerken und was macht ihn effektiv?", answerA = "Der Angreifer knackt den Password-Hash offline mit Brute-Force", answerB = "Pass-the-Hash erfordert immer physischen Zugang zum Zielrechner", answerC = "Der Angreifer extrahiert NTLM-Passwort-Hashes aus dem Speicher (z.B. lsass) und authentifiziert sich direkt mit dem Hash statt mit dem Klartextpasswort beim NTLM-Protokoll", answerD = "Pass-the-Hash funktioniert nur gegen veraltete Windows-XP-Systeme", correctAnswer = 2, explanation = "NTLM-Authentifizierung verwendet den Hash direkt — das Klartextpasswort wird nie uebertragen. Mit einem erbeuteten Hash kann sich ein Angreifer als jener Nutzer bei anderen Systemen authentifizieren, ohne das Passwort zu kennen.", difficulty = 3, funFact = "Mimikatz, ein Open-Source-Tool von Benjamin Delpy, machte Pass-the-Hash-Angriffe ab 2011 trivial ausfuehrbar. Microsoft antwortete mit Credential Guard und Protected Users Security Group."),
    Question(categoryId = 7, questionText = "Was ist ein CNOT-Gatter im Quantencomputing und welche grundlegende Operation fuehrt es durch?", answerA = "CNOT ist das Quanten-Aequivalent des klassischen NOT-Gatters", answerB = "CNOT misst den Zustand zweier Qubits ohne sie zu veraendern", answerC = "CNOT (Controlled-NOT) flippt das Target-Qubit genau dann wenn das Control-Qubit |1> ist; es ist universell zusammen mit Einqubit-Gattern und erzeugt Verschraenkung wenn das Control-Qubit in Superposition ist", answerD = "CNOT ist ein Drei-Qubit-Gatter das drei Eingaben verarbeitet", correctAnswer = 2, explanation = "CNOT|00>=|00>, CNOT|01>=|01>, CNOT|10>=|11>, CNOT|11>=|10>. Angewendet auf H|0>x|0> erzeugt es den Bell-Zustand (|00>+|11>)/sqrt(2) — maximale Verschraenkung.", difficulty = 3, funFact = "Zusammen mit dem Hadamard-Gatter und der T-Phase ist CNOT universell fuer Quantencomputing: Jede Quantenoperation kann aus diesen drei Gattern aufgebaut werden."),
    Question(categoryId = 7, questionText = "Was ist ein Kalman-Filter in der Robotik und fuer welchen Zweck wird er eingesetzt?", answerA = "Ein Kalman-Filter ist ein neuronales Netz fuer Bildklassifikation", answerB = "Ein Kalman-Filter filtert Rauschen aus Audioaufnahmen", answerC = "Ein Kalman-Filter ist ein rekursiver Schaetzer der aus verrauschten Sensorwerten den optimalen Zustandsschaetzer berechnet indem er Systemmodell und Messungen gewichtet kombiniert", answerD = "Ein Kalman-Filter ist nur fuer lineare Systeme anwendbar und wird in der Robotik nie eingesetzt", correctAnswer = 2, explanation = "Der Filter wechselt zwischen Praediktion (Systemmodell vorwaerts rechnen) und Update (Messung einbeziehen). Der Kalman-Gain gewichtet Modell vs. Messung nach deren Unsicherheit. Nichtlineare Systeme verwenden EKF oder UKF.", difficulty = 3, funFact = "Rudolf Kalman entwickelte den Filter 1960. Er war entscheidend fuer das Apollo-Navigationsprogramm, das ihn zur Trajektorienberechnung zum Mond verwendete."),
    Question(categoryId = 7, questionText = "Was ist das Diffie-Hellman-Schluesseltauschprotokoll und welches mathematische Problem liegt seiner Sicherheit zugrunde?", answerA = "Diffie-Hellman verschluesselt Daten mit einem gemeinsamen geheimen Schluessel der vorab ueber einen sicheren Kanal ausgetauscht wird", answerB = "DH-Sicherheit basiert auf der Schwierigkeit der Primfaktorzerlegung grosser Zahlen", answerC = "DH erlaubt zwei Parteien einen gemeinsamen geheimen Schluessel ueber einen unsicheren Kanal zu vereinbaren ohne sich vorher getroffen zu haben; Sicherheit basiert auf der Schwierigkeit des diskreten Logarithmusproblems", answerD = "Diffie-Hellman ist ein symmetrisches Verschluesselungsverfahren das AES verwendet", correctAnswer = 2, explanation = "Alice sendet g^a mod p, Bob g^b mod p. Beide berechnen g^(ab) mod p — das gemeinsame Geheimnis. Ein Lauscher sieht g^a und g^b, muss aber a oder b aus g^a berechnen — das diskrete Logarithmusproblem.", difficulty = 3, funFact = "DH wurde 1976 von Whitfield Diffie und Martin Hellman veroeffentlicht und revolutionierte die Kryptografie — erstmals war ein Schluesseltausch ohne sicheren Vorabkanal moeglich."),
    Question(categoryId = 7, questionText = "Was ist Privilege Escalation und was unterscheidet vertikale von horizontaler Privilege Escalation?", answerA = "Privilege Escalation bezeichnet immer das Erlangen von Root-Rechten", answerB = "Privilege Escalation setzt immer einen Buffer Overflow voraus", answerC = "Vertikal: Niedrigprivilegierter Nutzer erlangt hoehere Rechte (z.B. User zu Root); Horizontal: Nutzer greift auf Ressourcen anderer Nutzer gleicher Privilegienstufe zu", answerD = "Horizontale Privilege Escalation ist nur in Cloud-Umgebungen moeglich", correctAnswer = 2, explanation = "Ein Beispiel fuer horizontale PE: Ein Banknutzer manipuliert die Account-ID in einer URL um auf ein anderes Konto zuzugreifen (IDOR). Vertikale PE: Ein Webserver-Prozess nutzt eine Kernel-Luecke um root zu werden.", difficulty = 3, funFact = "Insecure Direct Object Reference (IDOR) — ein Fall horizontaler PE — stand jahrelang in den OWASP Top 10 und ist trotz einfacher Pruefbarkeit extrem haeufig in realen Anwendungen."),
    Question(categoryId = 7, questionText = "Was ist ein Supply-Chain-Angriff und welcher beruehmte Fall aus 2020 verdeutlicht das Ausmass?", answerA = "Ein Angriff auf physische Lieferketten fuer Hardware-Komponenten", answerB = "Supply-Chain-Angriffe betreffen ausschliesslich Open-Source-Software", answerC = "Ein Supply-Chain-Angriff kompromittiert Software oder Hardware bevor sie den Endnutzer erreicht; der SolarWinds-Angriff 2020 infizierte das Build-System und verteilte eine trojanisierte Orion-Update an 18.000 Kunden inklusive US-Regierungsbehoerden", answerD = "Der SolarWinds-Angriff war ein klassischer Phishing-Angriff ohne Supply-Chain-Komponente", correctAnswer = 2, explanation = "Die Angreifer (vermutlich APT29/Cozy Bear) kompromittierten den SolarWinds-Build-Server und injizierten SUNBURST-Malware in das Orion-Softwarepaket. Die signierten legitimen Updates wurden von Sicherheitssystemen der Opfer als vertrauenswuerdig eingestuft.", difficulty = 3, funFact = "SolarWinds hatte einen GitHub-Account mit dem Passwort 'solarwinds123'. Der Angriff blieb neun Monate unentdeckt. Er gilt als einer der gravierendsten Cyberspionage-Angriffe in der Geschichte der USA."),

    // correctAnswer = 3 (12 Fragen)
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Full Node und einem Light Client (SPV) in einer Blockchain?", answerA = "Full Nodes und Light Clients sind identisch in ihrer Funktionalitaet", answerB = "Light Clients sind unsicherer als Full Nodes weil sie keine Transaktionen pruefen", answerC = "Full Nodes sind nur fuer Mining notwendig", answerD = "Ein Full Node laedt und validiert alle Transaktionen und Bloecke seit Genesis; ein SPV-Client laedt nur Block-Header und prueft Transaktionen per Merkle-Beweis ohne alle Transaktionen zu kennen", correctAnswer = 3, explanation = "SPV (Simplified Payment Verification) erlaubt es Smartphones, Bitcoin-Transaktionen zu verifizieren ohne die 500+ GB Blockchain herunterzuladen. Sie vertrauen darauf, dass die laengste Kette mit den meisten PoW korrekt ist.", difficulty = 3, funFact = "Satoshi beschrieb SPV bereits in Abschnitt 8 des Bitcoin-Whitepapers. Mobile Wallets wie Electrum und Bluewallet nutzen SPV um ressourcenarm sicher zu sein."),
    Question(categoryId = 7, questionText = "Was ist Fuzzing als Sicherheitstestmethode und was ist der Unterschied zwischen Blackbox- und Coverage-guided Fuzzing?", answerA = "Fuzzing ist manuelles Testen mit handgefertigten Eingaben", answerB = "Blackbox-Fuzzing hat immer eine hoehere Code-Coverage als Coverage-guided Fuzzing", answerC = "Fuzzing kann nur gegen Netzwerkprotokolle eingesetzt werden", answerD = "Fuzzing sendet automatisch zufaellig generierte oder mutierte Eingaben an ein Programm um Abstuerze zu provozieren; Coverage-guided Fuzzing (AFL, libFuzzer) instrumentiert das Programm um Code-Coverage zu messen und gezielt neue Pfade zu erkunden", correctAnswer = 3, explanation = "Coverage-guided Fuzzer behalten Eingaben die neue Code-Pfade entdecken als 'interessant' und mutieren sie weiter. Dies findet tiefe Bugs die rein zufaellige Eingaben nie erreichen wuerden.", difficulty = 3, funFact = "Google OSS-Fuzz hat seit 2016 ueber 10.000 Sicherheitsluecken in Open-Source-Software gefunden darunter kritische Bugs in OpenSSL, FFmpeg und dem Linux-Kernel."),
    Question(categoryId = 7, questionText = "Was ist Grovers Algorithmus und welchen quadratischen Geschwindigkeitsvorteil bietet er?", answerA = "Grovers Algorithmus sortiert eine unsortierte Liste in O(n) Zeit statt O(n log n)", answerB = "Grovers Algorithmus loest Sudoku-Raetsel exponentiell schneller als klassische Computer", answerC = "Grovers Algorithmus bietet exponentiellen Speedup fuer alle Suchprobleme", answerD = "Grovers Algorithmus durchsucht eine unsortierte Datenbank mit N Eintraegen in O(sqrt(N)) Schritten statt O(N) klassisch — ein quadratischer Speedup", correctAnswer = 3, explanation = "Der quadratische Speedup halbiert effektiv die Bitlaenge von symmetrischen Schluesseln: AES-128 bietet gegen einen Quantenangreifer nur noch die Sicherheit von AES-64. Deshalb empfiehlt NIST AES-256 als post-quantum-sicher.", difficulty = 3, funFact = "Grover bewies 1996, dass sein Algorithmus optimal ist — kein Quantenalgorithmus kann eine unsortierte Suche besser als O(sqrt(N)) loesen."),
    Question(categoryId = 7, questionText = "Was ist Quantum Error Correction (QECC) in Quantencomputern und warum ist es fundamental anders als klassische Fehlerkorrektur?", answerA = "QECC ist identisch mit klassischer ECC und benoetigt keine Sonderbehandlung", answerB = "Quantencomputer benoetigen keine Fehlerkorrektur da Quantenoperationen fehlerfrei sind", answerC = "QECC misst alle physischen Qubits direkt um Fehler zu erkennen", answerD = "Quantenfehlerkorrektur muss Fehler korrigieren ohne den Quantenzustand zu messen (was ihn kollabieren wuerde); sie kodiert ein logisches Qubit in mehrere physische Qubits um Fehler durch Syndrom-Messung zu erkennen", correctAnswer = 3, explanation = "Der No-Cloning-Satz verbietet einfaches Kopieren von Qubits wie bei klassischer Redundanz. Stattdessen werden Qubits verschraenkt und Fehler durch Ancilla-Qubits und Syndrom-Messungen erkannt ohne den logischen Zustand zu stoeren.", difficulty = 3, funFact = "Shors 9-Qubit-Code (1995) war der erste QECC. Der Surface-Code gilt heute als praktischster QECC: Er benoetigt ~1.000 physische Qubits pro logischem Qubit bei heutigen Fehlerraten."),
    Question(categoryId = 7, questionText = "Was ist ein ROP-Chain-Angriff auf eine ASLR+NX-gesicherte Anwendung und wie wird ein Info-Leak dafuer benoetigt?", answerA = "Ein ROP-Chain-Angriff umgeht NX durch das Einschleusen von Shellcode in den Stack", answerB = "ASLR und NX zusammen sind gegen alle ROP-Angriffe immun", answerC = "ROP-Chains koennen ohne Kenntnis der Speicherlayouts konstruiert werden", answerD = "Ein Info-Leak liest eine Adresse aus dem Prozessspeicher um die ASLR-Basis zu berechnen; anschliessend werden Gadget-Adressen relativ zur Basis berechnet und als ROP-Chain auf dem Stack platziert", correctAnswer = 3, explanation = "Typisches Exploit-Schema: Format-String-Bug leckt printf-Adresse → Basisadresse von libc = geleckte Adresse minus Offset → ROP-Gadgets bei bekannten Offsets in libc → system('/bin/sh') aufrufen.", difficulty = 3, funFact = "Pwntools ist ein Python-Framework das ROP-Chains automatisch generiert. Es durchsucht Binaerdateien nach Gadgets und verkettet sie zur gewuenschten Aktion."),
    Question(categoryId = 7, questionText = "Was ist ein Hardware-Trojaner und welche Phase des Chip-Entwurfs gilt als besonders anfaellig dafuer?", answerA = "Ein Hardware-Trojaner ist ein Softwarevirus der Treiber infiziert", answerB = "Hardware-Trojaner sind ein rein theoretisches Konzept ohne praktische Bedrohung", answerC = "Hardware-Trojaner werden ausschliesslich in der BIOS-Firmware implementiert", answerD = "Ein Hardware-Trojaner ist boesartige Schaltlogik die in einen Chip eingebettet wird; besonders anfaellig ist die Fab-Phase (Halbleiterfertigung) oder die EDA-Tool-Lieferkette bei der ein Angreifer Netlist-Manipulationen vornehmen kann", correctAnswer = 3, explanation = "Ein Hardware-Trojaner kann einen Kryptoalgorithmus schwaechen, ein Hintertuer oeffnen oder den Chip unter bestimmten Bedingungen sabotieren. Die Fertigung in nicht-vertrauenswuerdigen Foundries ist das groesste Risiko.", difficulty = 3, funFact = "Das DARPA TRUST-Programm und IARPA SHIELD forschen an Hardware-Trojaner-Erkennung. Vollstaendige Verifikation eines komplexen Chips ist praktisch unmoeglich — es gibt keine generelle Loesung."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen LIDAR und monokularer Tiefenschaetzung in der Roboterwahrnehmung?", answerA = "LIDAR und monokulare Tiefenschaetzung liefern identische Ergebnisse mit unterschiedlicher Hardware", answerB = "Monokulare Tiefenschaetzung ist immer genauer als LIDAR", answerC = "LIDAR funktioniert nur in Innenraeumen, Kameras nur im Freien", answerD = "LIDAR misst direkt Entfernungen durch Laufzeitmessung von Laserpulsen (aktiv, praezise, teuer); monokulare Tiefenschaetzung schliesst aus einem einzelnen Kamerabild durch gelernte Priors auf Tiefe (passiv, guenstig, ungenauer)", correctAnswer = 3, explanation = "LIDAR erzeugt eine praezise Punktwolke unabhaengig von Texturen. Kamerabasierte Tiefenschaetzung versagt bei texturlosen Flaechen und skaliert schlecht. Autonome Fahrzeuge kombinieren oft beide Sensortypen.", difficulty = 3, funFact = "Das Solid-State-LIDAR hat den Preis von 75.000 USD (Velodyne HDL-64, 2007) auf unter 100 USD gebracht. Tesla setzt kontroverserweise ausschliesslich auf Kameras ohne LIDAR."),
    Question(categoryId = 7, questionText = "Was ist ein Side-Channel-Angriff am Beispiel von Spectre und Meltdown?", answerA = "Ein Angriff ueber unverschluesselte Seitenkanaele im Netzwerk", answerB = "Ein Angriff der nur den Browser-Cache betrifft", answerC = "Social Engineering ueber ungesicherte Kommunikationswege", answerD = "Die Ausnutzung von Informationen die durch physikalische Nebeneffekte (Timing, Cache-Zustand) austreten, nicht durch Softwarefehler; Spectre und Meltdown lesen Speicher anderer Prozesse ueber den CPU-Cache", correctAnswer = 3, explanation = "Spectre und Meltdown nutzen den Zustand des CPU-Caches als Seitenkanal. Durch spekulativ ausgefuehrten Code und anschliessendes Timing-Messen kann ein Prozess den Speicher anderer Prozesse auslesen.", difficulty = 3, funFact = "Spectre und Meltdown wurden im Januar 2018 veroeffentlicht und betrafen fast alle CPUs der letzten 20 Jahre. Die Patches reduzierten die Leistung mancher Server-Workloads um bis zu 30%."),
    Question(categoryId = 7, questionText = "Was ist homomorphe Verschluesselung und welche praktische Bedeutung hat sie fuer Cloud-Computing?", answerA = "Homomorphe Verschluesselung ist ein anderer Begriff fuer Ende-zu-Ende-Verschluesselung", answerB = "Homomorphe Verschluesselung verdoppelt die Rechenkraft von Cloud-Servern", answerC = "Homomorphe Verschluesselung ersetzt TLS fuer Webanwendungen", answerD = "Homomorphe Verschluesselung erlaubt Berechnungen auf verschluesselten Daten ohne Entschluesselung; das Ergebnis auf Chiffretexten entspricht verschluesselt dem Ergebnis der Berechnung auf den Klartexten", correctAnswer = 3, explanation = "Fully Homomorphic Encryption (FHE) erlaubt es, einer Cloud KI-Inferenz auf medizinischen Daten durchzufuehren ohne die Patientendaten je zu sehen. Der Cloud-Server rechnet auf verschluesselten Eingaben und gibt ein verschluesseltes Ergebnis zurueck.", difficulty = 3, funFact = "Craig Gentry loeste 2009 das offene FHE-Problem in seiner Dissertation. Aktuelle FHE-Implementierungen sind noch 1.000-1.000.000x langsamer als unverschluesselte Berechnungen."),
    Question(categoryId = 7, questionText = "Was ist das Model Checking-Verfahren in der formalen Verifikation und wo wird es in der Softwaresicherheit eingesetzt?", answerA = "Model Checking ist eine statische Analyse die nur Syntaxfehler prueft", answerB = "Model Checking ist nur auf Hardware anwendbar, nicht auf Software", answerC = "Model Checker koennen keine Liveness-Eigenschaften verifizieren", answerD = "Model Checking erschoepfend prueft ob ein endliches Systemmodell eine Spezifikation (z.B. in LTL/CTL) erfuellt indem alle erreichbaren Zustaende durchsucht werden; eingesetzt zur Verifikation sicherheitskritischer Protokolle", correctAnswer = 3, explanation = "AWS nutzte TLA+ (Model Checker) um Fehler in S3- und DynamoDB-Protokollen zu finden. Der bekannte Spin Model Checker prueft C-Code auf Deadlocks, Datenwettlaeufe und Protokollfehler.", difficulty = 3, funFact = "Model Checking wurde von Edmund Clarke, E. Allen Emerson und Joseph Sifakis entwickelt — sie erhielten dafuer 2007 den Turing Award. Es gibt ein State-Explosion-Problem: Zustaende wachsen exponentiell mit der Systemgroesse."),
    Question(categoryId = 7, questionText = "Was ist Differential Privacy und welche mathematische Garantie gibt es fuer den Schutz individueller Daten?", answerA = "Differential Privacy verhindert SQL-Injection-Angriffe auf Datenbanken", answerB = "Differential Privacy verschluesselt alle Datenbankeintraege einzeln", answerC = "Differential Privacy erfordert immer eine vollstaendig verschluesselte Datenbank als Grundlage", answerD = "Differential Privacy garantiert dass die Ausgabe einer Abfrage sich kaum aendert ob ein bestimmtes Individuum in der Datenbank ist oder nicht; formell durch den Datenschutzparameter Epsilon quantifiziert", correctAnswer = 3, explanation = "Fuer alle benachbarten Datensaetze D und D' gilt: P(M(D) in S) <= e^epsilon * P(M(D') in S). Ein kleines Epsilon bedeutet starken Datenschutz. Rauschen (Laplace/Gauss) wird zur Abfrage addiert um dies zu gewaehrleisten.", difficulty = 3, funFact = "Apple nutzt Differential Privacy seit iOS 10 um Tastaturvorschlaege und Emoji-Statistiken zu sammeln ohne individuelle Daten preiszugeben. Google nutzt es in Chrome fuer Nutzungsstatistiken."),
    Question(categoryId = 7, questionText = "Was ist das Konzept 'Defense in Depth' in der Cybersicherheit und welches klassische Analogiemodell verdeutlicht es?", answerA = "Defense in Depth bedeutet, die staerkste Firewall als einzige Verteidigungsschicht einzusetzen", answerB = "Defense in Depth ist eine offensive Sicherheitsstrategie um Angreifer zu irritieren", answerC = "Defense in Depth ist nur fuer physische Sicherheitssysteme anwendbar", answerD = "Defense in Depth schichtet mehrere unabhaengige Sicherheitsmechanismen sodass der Angreifer alle Schichten durchdringen muss; Analogie ist ein mittelalterliches Schloss mit Graben, Aussenmauer, Innenmauer und Bergfried", correctAnswer = 3, explanation = "Einzelne Sicherheitsmechanismen versagen. Eine Firewall kann umgangen werden; dann schuetzt Netzwerksegmentierung; dann EDR auf Endpoints; dann Least-Privilege; dann SIEM-Monitoring. Jede Schicht verzoegert den Angreifer.", difficulty = 3, funFact = "Der Begriff stammt urspruenglich aus der Militaerstrategie. In der IT wurde er durch die NSA-Publikation 'Defense in Depth' (2001) popularisiert und ist heute Kernprinzip jeder Enterprise-Sicherheitsarchitektur.")
)
